val name = "Alice"          // type inferred String
// name = "Bob"             // ❌ compile error

var counter = 0
counter += 1                // ✅

// val on a mutable object — reference is fixed, contents are not
val list: MutableList<Int> = mutableListOf(1, 2, 3)
list.add(4)                 // ✅ contents change
// list = mutableListOf()   // ❌ reference change

// Use immutable types when possible
val immutable: List<Int> = listOf(1, 2, 3) // List has no add/remove

// Top-level vs class member — same rules
class Order(val id: String, var status: String)
val o = Order("1", "new")
o.status = "shipped"        // mutate via var property
// o.id = "2"               // ❌ val property

// const val — compile-time constant (only on top-level / object members)
object Config {
  const val BASE_URL = "https://api.example.com"
}

fun render(name: String?) {
  // Safe call
  println(name?.length)              // null if name is null

  // Elvis — supply default
  val display = name ?: "Guest"

  // let — only run if non-null
  name?.let { println("hello, $it") }

  // !! — only when truly impossible to be null
  val length = name!!.length         // throws NPE if null
}

// Smart casts — compiler narrows the type after a null check
fun describe(x: String?): String {
  if (x == null) return "empty"
  // x is now String here, no need for ?.
  return "len=\${x.length}"
}

// requireNotNull / checkNotNull — throw with a message
val token = requireNotNull(authToken) { "Login first" }

// Late init — for properties initialised later (DI, lifecycle)
class MyVM {
  lateinit var repo: Repo
  fun isReady() = ::repo.isInitialized
}

// Java interop — platform types
// String! comes from Java; treat as nullable when in doubt

val numbers = listOf(1, 2, 3, 4, 5)
val doubled = numbers.map { it * 2 }            // [2,4,6,8,10]
val evens = numbers.filter { it % 2 == 0 }       // [2,4]
val total = numbers.sum()                        // 15
val grouped = numbers.groupBy { if (it % 2 == 0) "even" else "odd" }

val mutable = mutableListOf("a", "b")
mutable += "c"            // operator → add

val set = setOf(1, 2, 2, 3)                      // size 3
val map = mapOf("id" to 1, "name" to "Alice")

// Destructuring & operators
val (key, value) = "name" to "Alice"
for ((k, v) in map) println("$k=$v")

// Sequences for lazy evaluation on big chains
val result = (1..1_000_000)
  .asSequence()
  .map { it * it }
  .filter { it % 2 == 0 }
  .take(10)
  .toList()

// Read-only ≠ immutable — backing list could still mutate.
// For deep immutability use Kotlinx Immutable Collections (kotlinx.collections.immutable)

// Default + named args
fun greet(name: String, greeting: String = "Hello") = "$greeting, $name"
greet("Alice")                    // Hello, Alice
greet("Bob", greeting = "Hi")     // Hi, Bob

// Higher-order
fun retry(times: Int, block: () -> Unit) {
  repeat(times) { block() }
}
retry(3) { println("try") }

// Function reference (`::`) — pass a named function as a lambda
fun isEven(n: Int) = n % 2 == 0
listOf(1, 2, 3).filter(::isEven)

// Closure captures surrounding scope
fun makeCounter(): () -> Int {
  var count = 0
  return { ++count }
}
val c = makeCounter()
println(c())   // 1
println(c())   // 2

// Inline — avoid lambda allocation, allow non-local return
inline fun forEachQuick(list: List<Int>, block: (Int) -> Unit) {
  for (x in list) block(x)
}

// Lambda with multiple parameters & destructuring
val pairs = listOf(1 to "a", 2 to "b")
pairs.forEach { (n, s) -> println("$n: $s") }

// if as expression
val status: String = if (score >= 90) "A" else if (score >= 70) "B" else "F"

// when on a value
fun gradeLabel(score: Int) = when {
  score >= 90 -> "A"
  score >= 70 -> "B"
  else        -> "F"
}

// when matching value, type, range
fun describe(x: Any) = when (x) {
  0           -> "zero"
  in 1..9     -> "small"
  is String   -> "string of length ${x.length}"
  null        -> "null"
  else        -> "unknown"
}

// Sealed-class exhaustiveness — compiler forces all cases
sealed interface NetworkResult<out T>
data class Success<T>(val value: T) : NetworkResult<T>
data class Failure(val error: Throwable) : NetworkResult<Nothing>
object Loading : NetworkResult<Nothing>

fun <T> render(r: NetworkResult<T>): String = when (r) {
  is Success -> "ok"
  is Failure -> "err: \${r.error.message}"
  Loading    -> "..."
  // No else needed — sealed type is exhaustive
}

// try as expression
val n: Int = try { input.toInt() } catch (e: NumberFormatException) { 0 }

fun describe(x: Any) {
  if (x is String) {
    println(x.length)            // smart cast — x is String here
  }
  if (x !is Int) return
  println(x + 1)                  // smart cast — x is Int here
}

// Null check → smart cast
fun greet(name: String?) {
  if (name == null) return
  println(name.length)            // x is String, no ?.
}

// when + smart cast
sealed class Event
class Click(val x: Int) : Event()
class Move(val dx: Int, val dy: Int) : Event()

fun handle(e: Event) = when (e) {
  is Click -> e.x                 // smart cast
  is Move  -> e.dx + e.dy         // smart cast
}

// Smart cast doesn't work on mutable shared state
class Holder { var value: String? = null }
fun bug(h: Holder) {
  if (h.value != null) {
    // ❌ compile error — could change between threads
    // h.value.length
  }
  // Workaround — capture into a local
  val v = h.value
  if (v != null) println(v.length)
}

// `as?` — safe cast
val s: String? = anyValue as? String
